    69→template <class FactoryCb>
    70→class DynamicFilterConfigProviderImpl : public DynamicFilterConfigProviderImplBase,
    71→                                        public DynamicFilterConfigProvider<FactoryCb> {
    72→public:
    73→  DynamicFilterConfigProviderImpl(
    74→      FilterConfigSubscriptionSharedPtr& subscription,
    75→      const absl::flat_hash_set<std::string>& require_type_urls, ThreadLocal::SlotAllocator& tls,
    76→      ProtobufTypes::MessagePtr&& default_config, bool last_filter_in_filter_chain,
    77→      const std::string& filter_chain_type, absl::string_view stat_prefix,
    78→      const Network::ListenerFilterMatcherSharedPtr& listener_filter_matcher)
    79→      : DynamicFilterConfigProviderImplBase(subscription, require_type_urls,
    80→                                            last_filter_in_filter_chain, filter_chain_type),
    81→        listener_filter_matcher_(listener_filter_matcher), stat_prefix_(stat_prefix),
    82→        main_config_(std::make_shared<MainConfig>(tls)),
    83→        default_configuration_(std::move(default_config)){};
    84→
    85→  ~DynamicFilterConfigProviderImpl() override {
    86→    auto& tls = main_config_->tls_;
    87→    if (!tls->isShutdown()) {
    88→      tls->runOnAllThreads([](OptRef<ThreadLocalConfig> tls) { tls->config_ = {}; },
    89→                           // Extend the lifetime of TLS by capturing main_config_, because
    90→                           // otherwise, the callback to clear TLS worker content is not executed.
    91→                           [main_config = main_config_]() {
    92→                             // Explicitly delete TLS on the main thread.
    93→                             main_config->tls_.reset();
    94→                             // Explicitly clear the last config instance here in case it has its
    95→                             // own TLS.
    96→                             main_config->current_config_ = {};
    97→                           });
    98→    }
    99→  }
   100→
   101→  // Config::ExtensionConfigProvider
   102→  const std::string& name() override { return DynamicFilterConfigProviderImplBase::name(); }
   103→  OptRef<FactoryCb> config() override {
   104→    if (auto& optional_config = (*main_config_->tls_)->config_; optional_config.has_value()) {
   105→      return optional_config.value();
   106→    }
   107→    return {};
   108→  }
   109→
   110→  // Config::DynamicExtensionConfigProviderBase
   111→  absl::Status onConfigUpdate(const Protobuf::Message& message, const std::string&,
   112→                              Config::ConfigAppliedCb applied_on_all_threads) override {
   113→    const absl::StatusOr<FactoryCb> config_or_error = instantiateFilterFactory(message);
   114→    RETURN_IF_STATUS_NOT_OK(config_or_error);
   115→    update(config_or_error.value(), applied_on_all_threads);
   116→    return absl::OkStatus();
   117→  }
   118→
   119→  absl::Status onConfigRemoved(Config::ConfigAppliedCb applied_on_all_threads) override {
   120→    absl::optional<FactoryCb> cb;
   121→    if (default_configuration_) {
   122→      auto cb_or_error = instantiateFilterFactory(*default_configuration_);
   123→      RETURN_IF_STATUS_NOT_OK(cb_or_error);
   124→      cb = cb_or_error.value();
   125→    }
