    25→// Shared helper for recording the latest filter used.
    26→template <class T>
    27→void recordLatestDataFilter(const typename FilterList<T>::iterator current_filter,
    28→                            T*& latest_filter, const FilterList<T>& filters) {
    29→  // If this is the first time we're calling onData, just record the current filter.
    30→  if (latest_filter == nullptr) {
    31→    latest_filter = current_filter->get();
    32→    return;
    33→  }
    34→
    35→  // We want to keep this pointing at the latest filter in the filter list that has received the
    36→  // onData callback. To do so, we compare the current latest with the *previous* filter. If they
    37→  // match, then we must be processing a new filter for the first time. We omit this check if we're
    38→  // the first filter, since the above check handles that case.
    39→  //
    40→  // We compare against the previous filter to avoid multiple filter iterations from resetting the
    41→  // pointer: If we just set latest to current, then the first onData filter iteration would
    42→  // correctly iterate over the filters and set latest, but on subsequent onData iterations
    43→  // we'd start from the beginning again, potentially allowing filter N to modify the buffer even
    44→  // though filter M > N was the filter that inserted data into the buffer.
    45→  if (current_filter != filters.begin() && latest_filter == std::prev(current_filter)->get()) {
    46→    latest_filter = current_filter->get();
    47→  }
    48→}
