    52→void ActiveStreamFilterBase::commonContinue() {
    53→  if (!canContinue()) {
    54→    ENVOY_STREAM_LOG(trace, "cannot continue filter chain: filter={}", *this,
    55→                     static_cast<const void*>(this));
    56→    return;
    57→  }
    58→
    59→  // Set ScopeTrackerScopeState if there's no existing crash context.
    60→  ScopeTrackedObjectStack encapsulated_object;
    61→  absl::optional<ScopeTrackerScopeState> state;
    62→  if (parent_.dispatcher_.trackedObjectStackIsEmpty()) {
    63→    restoreContextOnContinue(encapsulated_object);
    64→    state.emplace(&encapsulated_object, parent_.dispatcher_);
    65→  }
    66→
    67→  ENVOY_STREAM_LOG(trace, "continuing filter chain: filter={}", *this,
    68→                   static_cast<const void*>(this));
    69→  ASSERT(!canIterate(),
    70→         "Attempting to continue iteration while the IterationState is already Continue");
    71→  // If iteration has stopped for all frame types, set iterate_from_current_filter_ to true so the
    72→  // filter iteration starts with the current filter instead of the next one.
    73→  if (stoppedAll()) {
    74→    iterate_from_current_filter_ = true;
    75→  }
    76→  allowIteration();
    77→
    78→  // Only resume with do1xxHeaders() if we've actually seen 1xx headers.
    79→  if (has1xxHeaders()) {
    80→    continued_1xx_headers_ = true;
    81→    do1xxHeaders();
    82→    // If the response headers have not yet come in, don't continue on with
    83→    // headers and body. doHeaders expects request headers to exist.
    84→    if (!parent_.filter_manager_callbacks_.responseHeaders()) {
    85→      return;
    86→    }
    87→  }
    88→
    89→  // Make sure that we handle the zero byte data frame case. We make no effort to optimize this
    90→  // case in terms of merging it into a header only request/response. This could be done in the
    91→  // future.
    92→  if (!headers_continued_) {
    93→    headers_continued_ = true;
    94→    doHeaders(complete() && !bufferedData() && !hasTrailers());
    95→  }
    96→
    97→  doMetadata();
    98→
    99→  // It is possible for trailers to be added during doData(). doData() itself handles continuation
   100→  // of trailers for the non-continuation case. Thus, we must keep track of whether we had
   101→  // trailers prior to calling doData(). If we do, then we continue them here, otherwise we rely
   102→  // on doData() to do so.
